from pathlib import Path
import ctypes
import sys

from tkinter import (
    Button,
    Canvas,
    Entry,
    Label,
    Tk,
    PhotoImage,
)

try:
    from PIL import Image, ImageTk
except ImportError:
    Image = None
    ImageTk = None


OUTPUT_PATH = Path(__file__).parent
ASSETS_PATH = OUTPUT_PATH / Path("assets/frame0")
IMAGE_REFS = []


def relative_to_assets(path: str) -> Path:
    return ASSETS_PATH / Path(path)


def load_photo_image(path: str):
    try:
        image = PhotoImage(file=path)
    except Exception:
        if Image is None or ImageTk is None:
            raise
        image = ImageTk.PhotoImage(Image.open(path))
    IMAGE_REFS.append(image)
    return image


def enable_dpi_awareness():
    if sys.platform != "win32":
        return
    try:
        ctypes.windll.shcore.SetProcessDpiAwareness(1)
    except Exception:
        try:
            ctypes.windll.user32.SetProcessDPIAware()
        except Exception:
            pass


def center_window(window, width, height):
    window.update_idletasks()
    x = int((window.winfo_screenwidth() - width) / 2)
    y = int((window.winfo_screenheight() - height) / 2)
    window.geometry(f"{width}x{height}+{x}+{y}")


enable_dpi_awareness()

# ---------------- WINDOW ----------------
window = Tk()
window.title("Security Awareness Quiz")
window.geometry("1440x1024")
window.configure(bg="#F4F4F4")
center_window(window, 1440, 1024)
window.resizable(False, False)

# ---------------- CANVAS ----------------
canvas = Canvas(
    window,
    bg="#F4F4F4",
    height=1024,
    width=1440,
    bd=0,
    highlightthickness=0,
    relief="ridge"
)
canvas.place(x=0, y=0)

# Left purple panel
canvas.create_rectangle(
    0,
    0,
    620,
    1024,
    fill="#8A3FFC",
    outline=""
)

# Title text
canvas.create_text(
    57,
    347,
    anchor="nw",
    text="Security\nAwareness\nQuiz",
    fill="#FFFFFF",
    font=("Helvetica", 96, "bold")
)

# Enter Name label
canvas.create_text(
    720,
    412,
    anchor="nw",
    text="Enter Name",
    fill="#000000",
    font=("Helvetica", 40, "bold")
)

# Input background (visual only)
canvas.create_rectangle(
    720,
    473,
    1357,
    550,
    fill="#F4F4F4",
    outline="#8D8D8D"
)

# Start Quiz text (visual)
canvas.create_text(
    1066,
    918,
    anchor="nw",
    text="Start Quiz",
    fill="#000000",
    font=("Helvetica", 40)
)

# Optional arrow image
try:
    arrow_image = load_photo_image(relative_to_assets("element_1.png"))
    canvas.create_image(1309, 941, image=arrow_image)
except Exception:
    pass

# ---------------- REAL WIDGETS ----------------

# Name Entry (REAL textbox)
name_entry = Entry(
    window,
    font=("Helvetica", 18),
    bd=0
)
name_entry.place(
    x=750,
    y=485,
    width=580,
    height=44
)

# Error label (hidden initially)
name_error_label = Label(
    window,
    text="Please enter your name before starting the quiz",
    fg="#DA1E28",
    bg="#F4F4F4",
    font=("Helvetica", 14)
)
name_error_label.place(x=750, y=540)
name_error_label.place_forget()


def start_quiz():
    name = name_entry.get().strip()

    if not name:
        name_error_label.place(x=750, y=540)
        return

    name_error_label.place_forget()
    print(f"Starting quiz for {name}")
    # Next step: switch to question screen


# Start Quiz Button (REAL button)
start_button = Button(
    window,
    text="Start Quiz",
    font=("Helvetica", 16),
    cursor="hand2",
    command=start_quiz
)
start_button.place(
    x=1060,
    y=915,
    width=200,
    height=50
)

# ---------------- MAIN LOOP ----------------
if __name__ == "__main__":
    window.mainloop()